mapper.select:
select

from order_info oi
left join customer c on oi.customer_id = c.id
left join service_item si on oi.service_item_id = si.id


        and oi.order_no like concat('%', #{orderNo}, '%')


        and c.name like concat('%', #{customerName}, '%')


        and oi.payment_method = #{paymentMethod}


        and oi.pay_status = #{payStatus}


        and oi.debt_status = #{debtStatus}


        and oi.order_status = #{orderStatus}


        and oi.create_time >= #{beginTime}


        and oi.create_time <= #{endTime}


order by oi.create_time desc

mapper.update:
update order_info
set order_status = #{orderStatus},
    update_time = #{updateTime}
where id = #{id}
